const originalTextNodes = new WeakMap();
const originalElementHtml = new WeakMap();
const originalElementText = new WeakMap();
const originalAttributes = new WeakMap();
let originalTitle = document.title;

function normalizeText(value) {
  return value.replace(/\s+/g, " ").trim();
}

function normalizeHtml(value) {
  return value
    .replace(/\s+/g, " ")
    .replace(/>\s+</g, "><")
    .trim();
}

function getCurrentLanguage() {
  return localStorage.getItem(LANGUAGE_KEY) === "zh" ? "zh" : "en";
}

function shouldSkipTextNode(node) {
  const element = node.parentElement;
  return (
    !element ||
    element.closest("pre, code, script, style, .language-toggle, .study-panel")
  );
}

function translateTextNode(node, language) {
  if (shouldSkipTextNode(node)) return;
  if (!originalTextNodes.has(node)) {
    originalTextNodes.set(node, node.textContent);
  }

  const original = originalTextNodes.get(node);
  const trimmed = normalizeText(original);
  if (!trimmed) return;

  if (language === "en") {
    node.textContent = original;
    return;
  }

  const translated = zhText[trimmed];
  if (!translated) {
    node.textContent = original;
    return;
  }

  const leading = original.match(/^\s*/)[0];
  const trailing = original.match(/\s*$/)[0];
  node.textContent = `${leading}${translated}${trailing}`;
}

function shouldTranslateElement(element) {
  return (
    element.matches("h1, h2, h3, p, li, th, td, figcaption, .checkpoint, .note, .summary, .mini-label, .resource-card strong, .resource-card span") &&
    !element.closest("pre, script, style, .language-toggle, .study-panel")
  );
}

function translateElementHtml(language) {
  document.querySelectorAll(".content h1, .content h2, .content h3, .content p, .content li, .content th, .content td, .content figcaption, .content .checkpoint, .content .note, .content .summary, .content .mini-label, .content .resource-card strong, .content .resource-card span").forEach((element) => {
    if (!shouldTranslateElement(element)) return;
    if (!originalElementHtml.has(element)) {
      originalElementHtml.set(element, element.innerHTML);
      originalElementText.set(element, normalizeText(element.textContent));
    }

    const original = originalElementHtml.get(element);
    if (language === "en") {
      element.innerHTML = original;
      return;
    }

    const translated = zhHtml[originalElementText.get(element)];
    element.innerHTML = translated || original;
  });
}

function translateAttributes(language) {
  document.querySelectorAll("[aria-label], [alt], meta[name='description']").forEach((element) => {
    ["aria-label", "alt", "content"].forEach((attribute) => {
      if (!element.hasAttribute(attribute)) return;
      let attributeMap = originalAttributes.get(element);
      if (!attributeMap) {
        attributeMap = {};
        originalAttributes.set(element, attributeMap);
      }
      if (!attributeMap[attribute]) {
        attributeMap[attribute] = element.getAttribute(attribute);
      }

      const original = attributeMap[attribute];
      if (language === "en") {
        element.setAttribute(attribute, original);
        return;
      }

      element.setAttribute(attribute, zhAttributeText[original] || zhText[original] || original);
    });
  });
}

function addLanguageToggle() {
  const header = document.querySelector(".site-header");
  if (!header || document.querySelector(".language-toggle")) return;

  const group = document.createElement("div");
  group.className = "language-toggle";
  group.setAttribute("role", "group");

  const english = document.createElement("button");
  english.type = "button";
  english.dataset.lang = "en";

  const chinese = document.createElement("button");
  chinese.type = "button";
  chinese.dataset.lang = "zh";

  group.append(english, chinese);
  header.appendChild(group);

  group.addEventListener("click", (event) => {
    const button = event.target.closest("button[data-lang]");
    if (!button) return;
    const language = button.dataset.lang;
    localStorage.setItem(LANGUAGE_KEY, language);
    applyLanguage(language);
  });
}

function updateLanguageToggle(language) {
  const copy = languageCopy[language] || languageCopy.en;
  const group = document.querySelector(".language-toggle");
  if (!group) return;

  group.setAttribute("aria-label", copy.label);
  group.querySelector("[data-lang='en']").textContent = copy.english;
  group.querySelector("[data-lang='zh']").textContent = copy.chinese;

  group.querySelectorAll("button").forEach((button) => {
    const active = button.dataset.lang === language;
    button.classList.toggle("active", active);
    button.setAttribute("aria-pressed", String(active));
  });
}

function translateStaticPage(language) {
  document.documentElement.lang = language === "zh" ? "zh-Hant" : "en";
  document.title = language === "zh" ? zhText[originalTitle] || originalTitle : originalTitle;

  translateElementHtml(language);

  const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT);
  const nodes = [];
  while (walker.nextNode()) nodes.push(walker.currentNode);
  nodes.forEach((node) => translateTextNode(node, language));
  translateAttributes(language);
}

function applyLanguage(language) {
  translateStaticPage(language);
  updateLanguageToggle(language);
  addStudyPanel();
}

